head.script:
	scwin.selectRow;
	scwin.usrId;
	/**
	 * 화면 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initScreen = function() {
		// 화면초기화 공통 함수 호출
		comLib.initForm($p, "ECSZZ1400000", {"initScreenCallback" : scwin.searchDatas});
	};

	/**
	 * 화면 초기 데이터들을 조회한다.
	 * @param
	 * @return
	 */
	scwin.searchDatas = function() {
		// 로그인한 사용자 ID 변수설정
		scwin.usrId = comLib.getUsrId();

		for (var t = tabControl.getTabCount() - 1; t >= 0; t--) {
			tabControl.setSelectedTabIndex(t);
		}

		// 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
		scwin.setAthrSysDivCd();
	};

	/**
	 * 공통 코드 조회 콜백
	 * @param
	 * @return
	 */
	scwin.setAthrSysDivCd = function() {
		var requestData = {};
		requestData.data = {"usrId" : scwin.usrId, "sysDivCd" : "SCM_0000"};

		var option = {action : "sc/authmng/retrieveAthrSysDivCd.do",
			reqData : requestData,
			resData : dltSysDivCdList,
			success : "scwin.retrieveAthrSysDivCdCallback",
			isShowMeg : false
		};
		ajaxLib.requestAjaxSyncCode($p, option);
	};

	/**
	 * 조회 CallBack 실행
	 * @param <Object> resBody
	 * @return
	 */
	scwin.retrieveAthrSysDivCdCallback = function(resBody, e) {
		if (dltSysDivCdList.getRowCount() == 0) {
			// 시스템관리자만 접근이 가능합니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00343"), "utilLib.winContainerClose");
			return;
		}

		var sysDivCd = comLib.getSysDivCd();

		dmaInqireParam.set("intnSysDivCd", sysDivCd);
		dmaInqireParam.set("usrId", scwin.usrId);

		scwin.inqireBtnInfo();
	};

	/**
	 * 버튼권한값 DB 가져오기
	 * @param
	 * @return
	 */
	scwin.inqireBtnInfo = function() {
		var requestData = {};
		requestData.dmaInqireParam = dmaInqireParam.getJSON();

		var option = {action : "zz/authmng/retrieveBtnInfo.do",
			reqData : requestData,
			resData : dltBtnAthrList,
			success : "scwin.inqireBtnInfoCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 버튼권한값 DB 가져오기
	 * @param
	 * @return
	*/
	scwin.inqireBtnInfoCallback = function(resBody, e) {
		if (resBody.message.code == "success") {
			if (dltBtnAthrList.getRowCount() > 0) {
				//console.log("조회된 데이터는 총 " + dltBtnAthrList.getRowCount() + " 건 입니다.");
			}
		}

		// 화면 오픈시 자동조회를 한다.
		comLib.setEnterKeyEvent(grpInqire, scwin.btnInqire_onclick);
		comLib.setEnterKeyEvent(grpInqireMenu, scwin.btnInqireMenu_onclick);
		comLib.setEnterKeyEvent(grpInqireUsr, scwin.btnInqireUsr_onclick);
		scwin.btnInqire_onclick();
	};

	/**
	 * 권한목록을 조회한다.
	 * @param
	 * @return
	 */
	scwin.btnInqire_onclick = function() {
		var requestData = {};
		requestData.dmaInqireParam = dmaInqireParam.getJSON();
		var option = {
			//action : "zz/authmng/retrieveAthr.do",
			action : "zz/authmng/retrieveAthrEcs.do",
			reqData : requestData,
			resData : dltAthrList,
			success : "scwin.inqireCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.inqireCallback = function(resBody) {
		if (resBody.message.code == "success") {
			txtCnt.setValue(dltAthrList.getRowCount());

			// 권한ID는 읽기 속성으로 설정 변경
			for (var idx = 0; idx < dltAthrList.getRowCount(); idx++) {
				grdAthrList.setCellReadOnly(idx, "athrId", true);
				grdAthrList.setCellReadOnly(idx, "idvinfoDealYn", true);
			}
		} else {
			comLib.alert($p, "fail");
		}
	};

	/**
	 * 권한그룹 행 추가
	 * @param
	 * @return
	 */
	scwin.btnAddRowAthr_onclick = function() {
		var insertIndex = dltAthrList.insertRow();
		dltAthrList.setCellData(insertIndex, "intnSysDivCd", comLib.getSysDivCd());
		grdAthrList.setFocusedCell(insertIndex, "athrId", true);
	};

	/**
	 * 권한그룹 행 삭제
	 * @param
	 * @return
	 */
	scwin.btnDelRowAthr_onclick = function() {
		var selectRowIndex = grdAthrList.getFocusedRowIndex();
		var rowStat = dltAthrList.getRowStatus(selectRowIndex);
		var strAthrId = "";

		if (rowStat != "C") {
			//dltAthrList.deleteRow(selectRowIndex);
			strAthrId = dltAthrList.getCellData(selectRowIndex, "athrId");

			if (strAthrId != null || strAthrId != "") {
				dmaSaveAthr.setJSON(dltAthrList.getRowJSON(selectRowIndex));
				scwin.inqireAthrUse(selectRowIndex);
			} else {
				// 삭제하고자 하는 데이터 선택 후 삭제하도록 알림
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00252"));
			}
		} else {
			dltAthrList.removeRow(selectRowIndex);
		}
	};

	/**
	 * 권한 삭제전 등록된 정보가 있는지 확인한다.
	 * @param
	 * @return
	 */
	scwin.inqireAthrUse = function(rowIndex) {
		var requestData = {};
		requestData.dmaSaveAthr = dmaSaveAthr.getJSON();

		scwin.selectRow = rowIndex;

		var option = {action : "zz/authmng/selectAthrUse.do",
			reqData : requestData,
			resData : dmaInqireAthrUse,
			success : "scwin.inqireAthrUseCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 권한 삭제전 등록된 정보조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.inqireAthrUseCallback = function(resBody) {
		var menuCnt = 0;
		var usrCnt = 0;

		if (resBody.message.code == "success") {
			menuCnt = dmaInqireAthrUse.get("menuCnt");
			usrCnt = dmaInqireAthrUse.get("usrCnt");

			if (menuCnt == 0 && usrCnt == 0) {
				dltAthrList.deleteRow(scwin.selectRow);
				// scwin.btnDel_onclick();
			} else {
				// 사용중인 권한그룹은 삭제 못하도록 메세지 알림
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00246", dltAthrList.getCellData(grdAthrList.getFocusedRowIndex(), "athrNm")));
			}
		}
	};

	/**
	 * 권한그룹그리드에서 특정권한그룹을 선택시 해당 그룹의 메뉴조회를 한다.
	 * @param <Int> row
	 * @param <Int> col
	 * @return
	 */
	scwin.grdAthrList_oncellclick = function(row, col) {
		var rowIndex = row;
		var colIndex = col;

		var strAthrId = dltAthrList.getCellData(rowIndex, "athrId");
		var tabIndex = tabControl.getSelectedTabIndex();

		if (colIndex == 0) {
			if (strAthrId != null && strAthrId != "" && dltAthrList.getRowStatus(rowIndex) != "C") {
				dmaInqireMenuAthr.set("athrId", strAthrId);
				dmaInqireMenuAthr.set("intnSysDivCd", comLib.getSysDivCd());
				dmaInqireMenuAthr.set("menuNm", "");

				dmaInqireUsrAthr.set("athrId", strAthrId);
				dmaInqireUsrAthr.set("intnSysDivCd", comLib.getSysDivCd());

				if (tabIndex == 0) {
					scwin.btnInqireMenu_onclick();
				} else {
					scwin.btnInqireUsr_onclick();
				}
			} else {
				dmaInqireMenuAthr.reset();
				dmaInqireUsrAthr.reset();
				utilLib.clearDcObj(dltMenuAthrList);
				utilLib.clearDcObj(dltUsrAthrList);
			}
		}
	};

	/**
	 * 탭 변경에 따라 조회
	 * @param
	 * @return
	 */
	scwin.tabControl_ontabclick = function(tabID, idx) {
		if (idx == 0) {
			scwin.btnInqireMenu_onclick();
		} else {
			scwin.btnInqireUsr_onclick();
		}
	};

	/**
	 * 권한그룹에서 선택한 권한을 기준으로 메뉴에 설정된 정보를 조회한다.
	 * @param
	 * @return
	 */
	scwin.btnInqireMenu_onclick = function() {
		var athrId = dmaInqireMenuAthr.get("athrId");
		var intnSysDivCd = dmaInqireMenuAthr.get("intnSysDivCd");

		if (athrId == "" || intnSysDivCd == "") {
			// comLib.alert($p, utilLib.getMessage("SCM.INFO.00004", "권한ID"));
			return;
		}

		var requestData = {};
		requestData.dmaInqireMenuAthr = dmaInqireMenuAthr.getJSON();

		var option = {action : "zz/authmng/retrieveIntnAthrMenu.do",
			reqData : requestData,
			resData : dltMenuAthrList,
			success : "scwin.inqireMenuCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.inqireMenuCallback = function(resBody) {
		if (resBody.message.code == "success") {
			//console.log("조회된 데이터는 총 " + dltMenuAthrList.getRowCount() + " 건 입니다.");

			if (dltMenuAthrList.getRowCount() > 0) {
				var inqireAthrId = dmaInqireMenuAthr.get("athrId");

				for (var idx = 0; idx < dltMenuAthrList.getRowCount(); idx++) {
					var athrId = dltMenuAthrList.getCellData(idx, "athrId");

					if (athrId != null && athrId != "") {
						dltMenuAthrList.setCellData(idx, "grantYn", "Y");
						grdMenuAthrList.setCellReadOnly(idx, "btnAthrList", false);
					} else {
						dltMenuAthrList.setCellData(idx, "athrId", inqireAthrId);
						dltMenuAthrList.setCellData(idx, "grantYn", "N");
						grdMenuAthrList.setCellReadOnly(idx, "btnAthrList", true);
					}
				}

				dltMenuAthrList.modifyAllStatus("R");
			}
		} else {
			comLib.alert($p,  "fail");
		}
	};

	 /**
	 * 그리드의 내용을 엑셀로 다운로드 한다.
	 * @param
	 * @return
	 */
	scwin.btnDownExcel_onclick = function() {
		var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
		var subTitleNm1 = spnSubTitle.getValue();
		var subTitleNm2 = document.getElementById($p.id + "tabControl_tab_tabLogin_tabHTML").title;
		// 엑셀 내부 타이틀 추가_240108
		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 7,
			text 		: `${menuNm}_` + `${subTitleNm1}(` + `${subTitleNm2})`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);

		comLib.downloadExcel(grdMenuAthrList, {
			fileName : `${menuNm}_` + `${subTitleNm1}(` + `${subTitleNm2}).xlsx`,
			type : 1,
			autoSizeColumn : true,
			startRowIndex : 1,
			startColumnIndex : 0,
			useDataFormat: true,
			applyDataFormat : true,
			useHeaderCheckBoxLabel : true,
			useHeaderDataFormat : true
		}, infoArr);
	};

	/**
	 * 해더 클릭 시 자동 체크되도록 한다.
	 * @param <Object> info
	 * @return
	 */
	scwin.grdMenuAthrList_onheaderclick = function(headerId) {
		if (headerId == "hGrantYn") {
			for (var idx = 0; idx < dltMenuAthrList.getRowCount(); idx++) {
				if (dltMenuAthrList.getCellData(idx, "grantYn") == "Y") {
					grdMenuAthrList.setCellReadOnly(idx, "btnAthrList", false);
					dltMenuAthrList.setCellData(idx, "btnAthrList", "Q,S,D,N,CC,E,EU");
					dltMenuAthrList.modifyRowStatus(idx, "C");
				} else {
					grdMenuAthrList.setCellReadOnly(idx, "btnAthrList", true);
					dltMenuAthrList.setCellData(idx, "btnAthrList", "");
					dltMenuAthrList.deleteRow(idx);
				}
			}
		}
	}

	/**
	 * 체크박스 이벤트
	 * @param
	 * @return
	 */
	scwin.grdMenuAthrList_onviewchange = function(info) {
		var targetRow = info.rowIndex;
		var targetCol = info.colIndex;
		var oldValue = info.oldValue;
		var newValue = info.newValue;

		if (targetCol == 2) {
			if (newValue == "Y") {
				grdMenuAthrList.setCellReadOnly(targetRow, "btnAthrList", false);
				dltMenuAthrList.setCellData(targetRow, "btnAthrList", "Q,S,D,N,CC,E,EU");
				dltMenuAthrList.modifyRowStatus(targetRow, "C");
			} else {
				grdMenuAthrList.setCellReadOnly(targetRow, "btnAthrList", true);
				dltMenuAthrList.setCellData(targetRow, "btnAthrList", "");
				dltMenuAthrList.deleteRow(targetRow); // "D"
			}
		}
	};

	/**
	 * 권한그룹에서 선택한 권한을 기준으로 메뉴에 설정된 정보를 조회한다. 
	 * @param
	 * @return
	 */
	scwin.btnInqireUsr_onclick = function() {
		// 권한ID를 지정하고 조회하도록 한다.
		var athrId = dmaInqireUsrAthr.get("athrId");

		if (athrId == "") {
			// comLib.alert($p, utilLib.getMessage("SCM.INFO.00004", "권한ID"));
			return;
		}

		var requestData = {};
		requestData.dmaInqireUsrAthr = dmaInqireUsrAthr.getJSON();

		var option = {action : "zz/authmng/retriebeUsrAthrGrp.do",
			reqData : requestData,
			resData : dltUsrAthrList,
			success : "scwin.inqireCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 사용자권한 추가
	 * @param
	 * @return
	 */
	scwin.btnAddRowUsr_onclick = function() {
		scwin.inqireUsr();
	};

	/**
	 * 사용자 조회
	 * @param
	 * @return
	 */
	scwin.inqireUsr = function() {
		var url = comLib.HRM_POP_URL + "/ui/hrm/zz/searchmng/HRMZZ20000007.xml";

		//팝업창 옵션
		var option = {popupID : "HRMZZ20000007",
			width : 800,
			height : 500,
			title : "사원 조회"
		};

		var strEnc = comLib.dataDecEnc(utilLib.getDate(), "E"); //암호화 키값
		var usrInfo; //세션정보 및 윈도우 타이틀

		usrInfo = JSON.stringify(comLib.getUserInfo4Param(strEnc, encodeURI(option.title)));

		var jsonObj = {
			// 필수값
			userInfo : usrInfo,
			closeCallbackFncName : "scwin.inqireUsrCallback",
			popupId : option.popupID,
			// 선택값(팝업에 따라 적용)
			//, topDeptCd : "50041064"	// 특정 부서의 하위 부서만 조회하고 싶은 경우 입력
			//, selectedDeptCd : "50041580"	// 자동선택될 부서 ID, defaultDeptYn 보다 우선순위가 높음
			defaultDeptYn : "Y",	// 초기 로딩 시 로그인한 사용자 부서 자동 선택 여부
			multiCheckYn : "N",	// 다건 선택 여부
			treeCheckYn : "N"	// 조직트리 다건 선택 여부
		};

		comLib.openPostWinPopup($p, url, option, jsonObj);
	};

	/**
	 * 사용자 검색 CallBack 실행
	 * @param <Object> retirnValue
	 * @param <String> popupId
	 * @return
	 */
	scwin.inqireUsrCallback = function(returnValue, popupId) {
		var selectedOrg =  returnValue[0];

		// 사용자 중복체크
		for (var j = 0; j < dltUsrAthrList.getRowCount(); j++) {
			if (selectedOrg.usrId == dltUsrAthrList.getCellData(j, "usrId")) {
				// {0}(은/는) 중복될 수 없습니다.
				comLib.alert($p, utilLib.getMessage("SCM.INFO.00068", "사번"));
				return;
			}
		}

		var insertIndex = dltUsrAthrList.insertRow();

		grdUsrAthrList.setFocusedCell(insertIndex, "usrNm", true);
		dltUsrAthrList.setCellData(insertIndex, "athrId", dmaInqireUsrAthr.get("athrId"));
		dltUsrAthrList.setCellData(insertIndex, "usrId", selectedOrg.usrEmpno);
		dltUsrAthrList.setCellData(insertIndex, "usrEmpno", selectedOrg.usrEmpno);
		dltUsrAthrList.setCellData(insertIndex, "usrNm", selectedOrg.usrNm);
		dltUsrAthrList.setCellData(insertIndex, "usrDeptNm", selectedOrg.usrDeptNm);
		dltUsrAthrList.setCellData(insertIndex, "usrOfcpsNm", selectedOrg.usrOfcpsNm);
		dltUsrAthrList.setCellData(insertIndex, "usrJgrdNm", selectedOrg.usrJgrdNm);
		dltUsrAthrList.setCellData(insertIndex, "applcStrtDe", utilLib.getCurrentDate());
		dltUsrAthrList.setCellData(insertIndex, "applcEndDe", scwin.getEndDe());
	};

	/**
	 * 사용자권한 행 삭제
	 * @param
	 * @return
	 */
	scwin.btnDelRowUsr_onclick = function() {
		var selectRowIndex = grdUsrAthrList.getFocusedRowIndex();
		var rowStat = dltUsrAthrList.getRowStatus(selectRowIndex);

		if (rowStat != "C") {
			dltUsrAthrList.deleteRow(selectRowIndex);
		} else {
			dltUsrAthrList.removeRow(selectRowIndex);
		}
	};

	/**
	 * 다음 해의 1월말을 가져온다.
	 */
	scwin.getEndDe = function() {
		var today = new Date();
		var year = today.getFullYear();

		// 1월이면 년도를 바꾸지 않고 날짜만 31일로 바꾼다.(?)
		if (today.getMonth() > 0) {
			year++;
		}

		return year + "0131";
	}

	/**
	* 변경된 데이터 저장, 수정한다.
	* @param
	* @return
	*/
	scwin.btnSave_onclick = function() {
		var valInfo = [
			{id : "athrId", mandatory : true},
			{id : "intnSysDivCd", mandatory : true},
			{id : "athrNm", mandatory : true}
		];

		var valInfoMenu = [
			{id : "menuId", mandatory : true}
		];

		var valInfoUsr = [
			{id : "athrId", mandatory : true},
			{id : "usrId", mandatory : true}
		];

		if ((dltAthrList.getModifiedData() == "") &&
			(dltMenuAthrList.getModifiedData() == "") &&
			(dltUsrAthrList.getModifiedData() == "")) {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		// 중복체크
		var insertList = dltAthrList.getInsertedJSON();

		if (insertList != null && insertList.length > 0) {
			for (var idx = 0; idx < insertList.length; idx++) {
				for (var j = 0; j < dltAthrList.getRowCount(); j++) {
					if (dltAthrList.getRowStatus(j) != "C" && insertList[idx].athrId == dltAthrList.getCellData(j, "athrId")) {
						// {0}(은/는) 중복될 수 없습니다.
						comLib.alert($p, utilLib.getMessage("SCM.INFO.00068", "권한ID"));
						return;
					}
				}
			}
		}

		if ((utilLib.validateGridView(grdAthrList, valInfo)) &&
			(utilLib.validateGridView(grdMenuAthrList, valInfoMenu)) &&
			(utilLib.validateGridView(grdUsrAthrList, valInfoUsr))) {
			// 저장할것인지 confirm
			comLib.confirm($p, utilLib.getMessage("SCM.INFO.00239"), "scwin.saveConfirmCallback");
		}
	};

	/**
	 * 수정/저장 saveConfirmCallback 실행한다.
	 * @param
	 * @return
	 */
	scwin.saveConfirmCallback = function() {
		var requestData = {};
		requestData.dltAthrList = dltAthrList.getModifiedJSON();
		requestData.dltMenuAthrList = dltMenuAthrList.getModifiedJSON();
		requestData.dltUsrAthrList = dltUsrAthrList.getModifiedJSON();

		var option = {action : "zz/authmng/saveAthrMng.do",
			reqData : requestData,
			success : "scwin.saveAthrMngCallback",
			savedToken : true,
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 수정/저장 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.saveAthrMngCallback = function(resBody) {
		comLib.alert($p, resBody.message.code_name);

		if (dltAthrList.getModifiedJSON().length > 0) {
			scwin.btnCancl_onclick();
		} else {
			dltMenuAthrList.setJSON([]);
			dltUsrAthrList.setJSON([]);

			if (tabControl.getSelectedTabIndex() == 0) {
				scwin.btnInqireMenu_onclick();
			} else {
				scwin.btnInqireUsr_onclick();
			}
		}
	};

	/**
	 * 작업내용 취소
	 * @param
	 * @return
	 */
	scwin.btnCancl_onclick = function() {
//		dmaInqireParam.reset();
		dmaInqireMenuAthr.reset();
		dmaInqireUsrAthr.reset();

		dltAthrList.removeAll();
		dltMenuAthrList.removeAll();
		dltUsrAthrList.removeAll();

//		dmaInqireParam.set("intnSysDivCd", comLib.getSysDivCd());

		scwin.btnInqire_onclick();
	};

	scwin.btnDel_onclick = function() {
		if ((dltMenuAthrList.getModifiedData() == "") &&
			(dltUsrAthrList.getModifiedData() == "")) {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		if (dltMenuAthrList.getModifiedData() != "") {
			comLib.deleteGridView(grdMenuAthrList);
		}

		if (dltUsrAthrList.getModifiedData() != "") {
			comLib.deleteGridView(grdUsrAthrList);
		}

		// 삭제할것인지 confirm
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00251"), "scwin.saveConfirmCallback");
	};
